    // Min-heap to store potential buy costs (as negative values for max-heap behavior, 
    // but actually we need min-heap so we use priority_queue with greater comparator)
    priority_queue<long long, vector<long long>, greater<long long>> pq;

    long long answer = 0;

    for (int i = 0; i < n; i++) {
        long long price = a[i];

        if (!pq.empty() && price - C > pq.top()) {
            // Sell at current price using the cheapest buy price
            long long buyCost = pq.top();
            pq.pop();
            answer += price - buyCost - C;

            // Regret mechanism: push new virtual buy points
            // Push (price - C) to allow "re-buying" at this level for future higher prices
            pq.push(price - C);
            // Also push price itself to allow holding from this point
            pq.push(price);
        } else {
            // Just record this price as a potential buy point
            pq.push(price);
        }
    }

    cout << answer << "\n";
    return 0;
}
